from prometheus_client import Collector, GaugeMetricFamily, Counter, Histogram
from flask import Flask, request, jsonify
import time

app = Flask(__name__)

requests_counter = Counter('http_requests_total', 'Total number of HTTP requests')
request_latency_histogram = Histogram('http_request_duration_seconds', 'HTTP request duration in seconds')
business_metric_gauge = Gauge('business_metric', 'Business metric value')

@app.route('/')
def home():
    business_metric_gauge.set(100)  # Set a mock business metric value for this example
    requests_counter.inc()
    start_time = time.time()
    response = jsonify({"message": "Hello, World!"})
    end_time = time.time()
    request_latency_histogram.observe(end_time - start_time)  # Record the latency of the request
    return response

if __name__ == '__main__':
    app.run(port=5000, debug=True)